// client/src/pages/ProductsPage.jsx
import React from 'react';
import SearchBar from '../components/SearchBar';
import FilterBox from '../components/FilterBox';
import ProductCard from '../components/ProductCard';
import './ProductsPage.css'; // Create this CSS file

const ProductsPage = () => {
    // Placeholder for products data
    const products = [
        { id: '1', name: 'Gaming Laptop', price: 1500, category: 'Laptops', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=Gaming+Laptop', description: 'Powerful laptop for gaming enthusiasts.' },
        { id: '2', name: 'Smartwatch', price: 299, category: 'Wearables', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=Smartwatch', description: 'Track your fitness and receive notifications.' },
        { id: '3', name: 'Wireless Earbuds', price: 120, category: 'Audio', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=Earbuds', description: 'High-quality sound with long battery life.' },
        { id: '4', name: '4K Smart TV', price: 999, category: 'Televisions', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=4K+TV', description: 'Immersive viewing experience with smart features.' },
        { id: '5', name: 'External SSD 1TB', price: 150, category: 'Storage', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=SSD', description: 'Fast and portable storage solution.' },
        { id: '6', name: 'Bluetooth Speaker', price: 75, category: 'Audio', imageUrl: 'https://placehold.co/300x200/cccccc/333333?text=Speaker', description: 'Portable speaker with rich sound.' },
    ];

    const handleSearch = (query) => {
        console.log('Searching for:', query);
        // In a real app, you'd fetch products based on query
    };

    const handleFilter = (filters) => {
        console.log('Applying filters:', filters);
        // In a real app, you'd fetch products based on filters
    };

    return (
        <div className="products-page container">
            <h1>Our Products</h1>
            <div className="products-header">
                <SearchBar onSearch={handleSearch} />
                <FilterBox onFilter={handleFilter} />
            </div>
            <div className="product-list-grid">
                {products.map(product => (
                    <ProductCard key={product.id} product={product} />
                ))}
            </div>
        </div>
    );
};

export default ProductsPage;
